import{_ as e}from"./_plugin-vue_export-helper-c27b6911.js";import{o as t,j as a,x as s}from"./app-7ad23691.js";const o={},i={class:"privacy-page"},r=s('<div class="page-header text-center mb-12" data-v-6e663036><h1 class="text-h3 font-weight-bold mb-0" data-v-6e663036>DATA PROTECTION AND PRIVACY POLICY</h1></div><div class="privacy-content" data-v-6e663036><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Introduction</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> KIDAN Global Limited values the privacy of our customers, partners, and employees. We are committed to protecting personal data in compliance with the Nigeria Data Protection Regulation (NDPR) and Global Data Protection Regulation (GDPR). This policy outlines how we collect, use, disclose, and safeguard personal data in our operations as an e-commerce, fashion, and lifestyle company. </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Scope of the Policy</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> This policy applies to all employees, contractors, partners, and third-party service providers who handle personal data collected by KIDAN Global Limited. It covers data collected via our website, mobile applications, social media platforms, and in any other manner related to our business activities. </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Data We Collect</h2><p class="text-body-1 mb-4" style="line-height:1.8;color:#333;" data-v-6e663036> We may collect the following types of personal data: </p><ul class="text-body-1 pl-6 mb-4" style="line-height:1.8;color:#333;" data-v-6e663036><li data-v-6e663036><strong data-v-6e663036>Personal Information:</strong> Name, email address, phone number, billing and shipping addresses.</li><li data-v-6e663036><strong data-v-6e663036>Payment Information:</strong> Credit/debit card details, bank account information (processed securely through third-party payment processors).</li><li data-v-6e663036><strong data-v-6e663036>Account Information:</strong> Username, password, purchase history, preferences.</li><li data-v-6e663036><strong data-v-6e663036>Technical Data:</strong> IP address, browser type, device information, cookies, and usage data.</li><li data-v-6e663036><strong data-v-6e663036>Marketing Data:</strong> Preferences for receiving promotional materials and communication history.</li></ul></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Legal Basis for Processing Personal Data</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> We process personal data in compliance with the NDPR &amp; GDPR based on one or more of the following legal grounds: Consent: When individuals provide clear and explicit consent; Contractual Necessity: When processing is necessary to fulfill our contractual obligations (e.g., order processing, delivery); Legal Obligation: When processing is required to comply with applicable laws and regulations; Legitimate Interests: Where processing is necessary for the legitimate business interests of KIDAN Global Limited, provided that such interests do not override the rights and freedoms of data subjects. How We Use Personal Data We use personal data for the following purposes: </p><ul class="text-body-1 pl-6 mt-4" style="line-height:1.8;color:#333;" data-v-6e663036><li data-v-6e663036>Order Processing: To process and fulfill customer orders.</li><li data-v-6e663036>Customer Service: To respond to inquiries, resolve issues, and provide support.</li><li data-v-6e663036>Marketing: To send promotional materials, product updates, and personalized recommendations (with consent).</li><li data-v-6e663036>Analytics: To analyze website traffic, user behavior, and improve our services.</li><li data-v-6e663036>Legal Compliance: To comply with legal obligations and prevent fraud.</li></ul></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Data Sharing and Disclosure</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> We do not sell personal data to third parties. However, we may share data with: Service Providers: Third-party vendors, such as payment processors, shipping companies, and marketing platforms, who help us deliver our services; Legal Authorities: When required by law, we may disclose personal data to legal authorities; Business Transfers: In the event of a merger, acquisition, or sale of assets, personal data may be transferred to third parties involved in the transaction. All third-party partners are required to process personal data in a manner consistent with this policy and the NDPR &amp; GDPR. </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Data Security</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> We implement industry-standard security measures to protect personal data from unauthorized access, disclosure, alteration, or destruction. These measures include: Encryption: Sensitive data such as payment information is encrypted during transmission; Access Control: Access to personal data is restricted to authorized personnel only; Regular Audits: We conduct regular security audits to identify and address potential vulnerabilities. In case of a data breach, we will notify affected individuals and relevant authorities within the legally required timeframe. </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Data Retention</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> We retain personal data only for as long as necessary to fulfill the purposes for which it was collected, or as required by law. Customer data related to transactions is typically retained for tax and accounting purposes. Data is maintained for a period of 7 years. </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Data Subject Rights</h2><p class="text-body-1 mb-4" style="line-height:1.8;color:#333;" data-v-6e663036> Under the NDPR &amp; GDPR, individuals have the following rights regarding their data: Right to Access: Request access to their personal data; Right to Rectification: Correct any inaccurate or incomplete data; Right to Erasure: Request the deletion of their data under certain circumstances; Right to Restrict Processing: Request the restriction of their data processing; Right to Data Portability: Obtain a copy of their data when feasible in a portable format; Right to Withdraw Consent: Withdraw consent at any time for data processing; Right to Object: Object to the processing of their personal data for direct marketing or other legitimate interests; Right to Withdraw Consent: Withdraw consent for processing activities based on consent. To exercise these rights, individuals may connect to us: </p><p class="text-body-1 mb-2" style="line-height:1.8;color:#333;" data-v-6e663036> Email: <strong data-v-6e663036>support@kidanglobal.com</strong></p><p class="text-body-1 mb-2" style="line-height:1.8;color:#333;" data-v-6e663036> Address: Anikis Estate, Oniru, Lagos State, Nigeria </p><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> No. 10 New Yidi Road, Jlorin, Kwara State, Nigeria </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Cookies and Tracking Technologies</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> We use cookies and similar tracking technologies to enhance user experience, gather analytics, and provide targeted advertising. Users can manage their cookie preferences through their browser settings. </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>International Data Transfers</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> In the course of providing our services, your personal data may be transferred to, stored, or processed in a country other than Nigeria. When such international transfers are necessary, we ensure that the receiving country provides an adequate level of data protection or that appropriate safeguards are in place, in accordance with the Nigeria Data Protection Regulation (NDPR). </p></div><div class="section mb-8" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Policy Updates</h2><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> We may update this policy from time to time to reflect changes in our practices or legal requirements. We will notify users of any significant changes through our website or by email. </p></div><div class="section mb-0" data-v-6e663036><h2 class="text-h5 font-weight-bold mb-4" data-v-6e663036>Contact Information</h2><p class="text-body-1 mb-2" style="line-height:1.8;color:#333;" data-v-6e663036> For any questions or concerns regarding this policy or data protection practices, please contact: </p><p class="text-body-1 mb-2" style="line-height:1.8;color:#333;" data-v-6e663036> Data Protection Officer (DPO) </p><p class="text-body-1" style="line-height:1.8;color:#333;" data-v-6e663036> KIDAN GLOBAL LIMITED </p></div></div>',2),n=[r];function l(d,c){return t(),a("div",i,n)}const v=e(o,[["render",l],["__scopeId","data-v-6e663036"]]);export{v as default};
